//! The cadence governor — "as fast as the system can handle stably".
//!
//! The decode pipe is serial (one ffmpeg stdout), so the parallelism lives in *processing*
//! decoded frames. Each batch of selected frames is processed via gnosis-frf, gated by the
//! value-door (cheap work runs serial/RED, real work runs parallel/GREEN), with processed
//! frame-events admitted through an antiqueue corridor. A stride controller watches how the
//! measured per-frame cost compares to the real-time budget and widens/narrows the sample
//! stride to converge on the maximum *stable* rate — it drops frames under load rather than
//! letting work pile up (antiqueue has no in-memory queue; back-pressure is frame-skip).
//!
//! P1 per-frame "work" is a real, cheap perception primitive — luma mean + a 16x16 luma
//! signature + frame-to-frame motion energy — standing in for the heavier vision of P2 and
//! already producing the motion signal P3's tracking will consume.

use frffmpeg::decode::{DecodeOptions, Decoder, Frame, probe};
use gnosis_antiqueue::{Broker, Chirality, Light, Stoplight, StoplightExt, certified_light};
use gnosis_frf::prelude::*;
use std::io;
use std::time::Instant;

/// A cheap, real per-frame readout. The 16x16 luma signature + motion energy are the seeds
/// the later tracking stage builds on.
#[derive(Clone)]
pub struct FrameStat {
    pub index: u64,
    pub pts_s: f64,
    pub luma_mean: f32,
    /// 16x16 downsampled luma (row-major), a cheap content fingerprint.
    pub sig: [u8; 256],
    /// Mean |Δ| of this frame's signature vs the previous, normalised to [0,1].
    pub motion: f32,
}

/// Compute the intra-frame stats (no cross-frame dependency, so this parallelises cleanly).
fn frame_stat(f: &Frame) -> FrameStat {
    let w = f.width as usize;
    let h = f.height as usize;
    let px = &f.rgb;
    let n = w * h;

    // Rec.601-ish integer luma, summed for the mean (single-source weights via `simd::luma_u8`).
    let mut sum: u64 = 0;
    for i in 0..n {
        sum += crate::simd::luma_u8(px[i * 3], px[i * 3 + 1], px[i * 3 + 2]) as u64;
    }
    let luma_mean = if n > 0 { sum as f32 / n as f32 } else { 0.0 };

    // 16x16 luma signature: average a sparse grid inside each cell.
    let mut sig = [0u8; 256];
    for by in 0..16usize {
        let y0 = by * h / 16;
        let y1 = ((by + 1) * h / 16).max(y0 + 1).min(h);
        let ystep = ((y1 - y0) / 4).max(1);
        for bx in 0..16usize {
            let x0 = bx * w / 16;
            let x1 = ((bx + 1) * w / 16).max(x0 + 1).min(w);
            let xstep = ((x1 - x0) / 4).max(1);
            let mut s: u64 = 0;
            let mut c: u64 = 0;
            let mut y = y0;
            while y < y1 {
                let mut x = x0;
                while x < x1 {
                    let i = (y * w + x) * 3;
                    s += crate::simd::luma_u8(px[i], px[i + 1], px[i + 2]) as u64;
                    c += 1;
                    x += xstep;
                }
                y += ystep;
            }
            sig[by * 16 + bx] = if c > 0 { (s / c) as u8 } else { 0 };
        }
    }

    FrameStat {
        index: f.index,
        pts_s: f.pts_s,
        luma_mean,
        sig,
        motion: 0.0,
    }
}

/// Normalised L1 distance between two signatures, in [0,1] (the SIMD-accelerated motion kernel).
fn sig_motion(a: &[u8; 256], b: &[u8; 256]) -> f32 {
    crate::simd::sig_motion_256(a, b)
}

/// Governor configuration.
#[derive(Debug, Clone)]
pub struct CadenceConfig {
    /// Desired real-time sample rate (frames/s) the governor tries to sustain.
    pub target_fps: f64,
    /// Frames processed per frf dispatch.
    pub batch: usize,
    /// Per-item platform dispatch cost (ns) for the value-door RED/GREEN decision.
    pub dispatch_ns: u64,
    /// Print a per-batch convergence line.
    pub verbose: bool,
}

impl Default for CadenceConfig {
    fn default() -> Self {
        CadenceConfig {
            target_fps: 30.0,
            batch: 16,
            dispatch_ns: 100, // mirrors GNOSIS_FRF_DISPATCH_NS default
            verbose: false,
        }
    }
}

/// What the governor converged on.
#[derive(Debug, Clone)]
pub struct CadenceReport {
    pub frames_decoded: u64,
    pub frames_processed: u64,
    pub frames_skipped: u64,
    /// Sample stride the controller settled on (process every Nth decoded frame).
    pub converged_stride: u32,
    /// Stable sample rate = source/decode fps ÷ converged stride.
    pub effective_fps: f64,
    /// Raw processing throughput the machine sustained (frames/s of actual work).
    pub processing_fps: f64,
    /// Wall-clock for the whole run (decode + process), seconds.
    pub wall_s: f64,
    /// Final value-door verdict for the per-frame work ("GREEN" parallel / "RED" serial).
    pub light: &'static str,
    /// antiqueue corridor telemetry.
    pub published: usize,
    pub delivered: usize,
    pub peak_in_flight: usize,
    /// Mean motion energy across processed frames, [0,1] (scene activity).
    pub mean_motion: f32,
}

fn light_name(l: Light) -> &'static str {
    match l {
        Light::Green => "GREEN",
        Light::Red => "RED",
        Light::Yellow => "YELLOW",
    }
}

/// Process one batch via the value-door: certify the per-frame cost, then run frf-parallel
/// (GREEN) or serial (RED). Returns ordered stats, the processing time, and the verdict.
fn process_batch(batch: &[Frame], dispatch_ns: u64) -> (Vec<FrameStat>, f64, Light) {
    if batch.is_empty() {
        return (Vec::new(), 0.0, Light::Red);
    }
    // Certify per-frame work cost by timing one frame (cert in hand -> never YELLOW).
    let t = Instant::now();
    let probe_stat = frame_stat(&batch[0]);
    let work_ns = (t.elapsed().as_nanos() as u64).max(1);
    let light = certified_light(work_ns, dispatch_ns);

    let t1 = Instant::now();
    let mut stats: Vec<FrameStat> = match light {
        Light::Green => batch
            .par_iter()
            .map(frame_stat)
            .with_sub_chunks_auto()
            .collect(),
        _ => batch.iter().map(frame_stat).collect(),
    };
    let dt = t1.elapsed().as_secs_f64();
    // Reuse the probe result for frame 0 (don't pay for it twice).
    if !stats.is_empty() {
        stats[0] = probe_stat;
    }
    (stats, dt, light)
}

/// Run the cadence governor over `path`. Decodes at `decode_fps` (None = source rate),
/// optionally scaling/capping, and converges the stride to hold `cfg.target_fps` stably.
pub fn run(
    path: &str,
    decode_fps: Option<f64>,
    scale: Option<(u32, u32)>,
    max_frames: Option<u64>,
    cfg: &CadenceConfig,
) -> io::Result<CadenceReport> {
    let info = probe(path)?;
    let src_fps = decode_fps.unwrap_or_else(|| info.fps()).max(1.0);

    let opts = DecodeOptions {
        fps: decode_fps,
        scale,
        start_s: None,
        max_frames,
    };
    let dec = Decoder::open(path, &info, &opts)?;

    // antiqueue corridor for processed frame-events. A finite green window expresses the
    // admission rate; peak_in_flight is the back-pressure signal the controller could also use.
    let broker = Broker::local();
    broker.declare_consumer_certified(
        "scene",
        Stoplight::resting(64, 8, 0),
        Chirality::Compression,
        0, // unattested handler -> default green-window gate
        |_m| Ok(()),
    );
    let producer = broker.producer("");

    let budget_ns = (1.0e9 / cfg.target_fps).max(1.0);
    let mut stride: u32 = 1;
    let mut sel_counter: u32 = 0;

    let mut decoded: u64 = 0;
    let mut processed: u64 = 0;
    let mut skipped: u64 = 0;
    let mut last_light = Light::Green;
    let mut proc_time_acc = 0.0f64;
    let mut motion_acc = 0.0f64;
    let mut prev_sig: Option<[u8; 256]> = None;

    let mut batch: Vec<Frame> = Vec::with_capacity(cfg.batch);
    let t0 = Instant::now();

    let flush = |batch: &mut Vec<Frame>,
                     stride: &mut u32,
                     last_light: &mut Light,
                     proc_time_acc: &mut f64,
                     motion_acc: &mut f64,
                     processed: &mut u64,
                     prev_sig: &mut Option<[u8; 256]>,
                     batch_no: usize| {
        if batch.is_empty() {
            return;
        }
        let (mut stats, dt, light) = process_batch(batch, cfg.dispatch_ns);
        *last_light = light;
        *proc_time_acc += dt;

        // Motion is a cross-frame fold; cheap, done serially after the parallel map.
        for s in stats.iter_mut() {
            if let Some(p) = prev_sig {
                s.motion = sig_motion(&s.sig, p);
            }
            *prev_sig = Some(s.sig);
            *motion_acc += s.motion as f64;
            // Admit the processed frame-event into the corridor.
            let _ = producer.publish_certified("scene.frame", s.sig.to_vec());
        }
        *processed += stats.len() as u64;

        // Controller: measured per-frame cost vs the real-time budget.
        let per_frame_ns = (dt * 1.0e9) / stats.len().max(1) as f64;
        let old = *stride;
        if per_frame_ns > budget_ns {
            *stride = (*stride + 1).min(240);
        } else if per_frame_ns < budget_ns * 0.5 && *stride > 1 {
            *stride -= 1;
        }
        if cfg.verbose {
            eprintln!(
                "batch {batch_no:>3}: {} frames {:>5}  {:.2} ms/frame  budget {:.2} ms  stride {} -> {}",
                stats.len(),
                light_name(light),
                per_frame_ns / 1.0e6,
                budget_ns / 1.0e6,
                old,
                *stride,
            );
        }
        batch.clear();
    };

    let mut batch_no = 0usize;
    for fr in dec {
        let fr = fr?;
        decoded += 1;
        // Stride selection: skip frames cheaply (no processing) under load.
        if sel_counter % stride != 0 {
            skipped += 1;
            sel_counter += 1;
            continue;
        }
        sel_counter += 1;
        batch.push(fr);
        if batch.len() >= cfg.batch {
            flush(
                &mut batch,
                &mut stride,
                &mut last_light,
                &mut proc_time_acc,
                &mut motion_acc,
                &mut processed,
                &mut prev_sig,
                batch_no,
            );
            batch_no += 1;
        }
    }
    // Tail.
    flush(
        &mut batch,
        &mut stride,
        &mut last_light,
        &mut proc_time_acc,
        &mut motion_acc,
        &mut processed,
        &mut prev_sig,
        batch_no,
    );

    let wall = t0.elapsed().as_secs_f64();
    let processing_fps = if proc_time_acc > 0.0 {
        processed as f64 / proc_time_acc
    } else {
        0.0
    };
    let tel = broker.telemetry();
    Ok(CadenceReport {
        frames_decoded: decoded,
        frames_processed: processed,
        frames_skipped: skipped,
        converged_stride: stride,
        effective_fps: src_fps / stride as f64,
        processing_fps,
        wall_s: wall,
        light: light_name(last_light),
        published: tel.published,
        delivered: tel.delivered,
        peak_in_flight: tel.peak_in_flight,
        mean_motion: if processed > 0 {
            (motion_acc / processed as f64) as f32
        } else {
            0.0
        },
    })
}
